"""Static assets for the optional local operations console."""


CONTROL_HTML = r"""<!doctype html>
<html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>ChatGPTWeb Control</title>
<style>
:root{font-family:Inter,"Segoe UI",Arial,sans-serif;color:#17242b;background:#f4f7f6;--ink:#17242b;--muted:#64747b;--line:#d8e0df;--panel:#fff;--teal:#08766b;--teal-dark:#065c54;--teal-wash:#e3f3ef;--red:#aa3838;--amber:#875600;--amber-wash:#fff4d8}*{box-sizing:border-box}body{margin:0;min-width:320px;background:#f4f7f6}button,input{font:inherit}button{cursor:pointer}button:disabled{cursor:wait;opacity:.58}.shell{max-width:1380px;margin:0 auto;padding:26px clamp(16px,3vw,40px) 44px}.topbar{display:flex;justify-content:space-between;gap:24px;align-items:flex-start;padding:2px 0 24px;border-bottom:1px solid var(--line)}.brand{display:flex;gap:12px;align-items:center}.mark{display:grid;place-items:center;width:34px;height:34px;border-radius:7px;background:var(--teal);color:#fff;font-size:12px;font-weight:700}h1{margin:0;font-size:21px;letter-spacing:0}.subtitle{margin:4px 0 0;color:var(--muted);font-size:13px}.actions{display:flex;gap:8px;align-items:center;justify-content:flex-end;flex-wrap:wrap}.key{display:flex;align-items:center;padding:5px;border:1px solid var(--line);border-radius:6px;background:#fff}.key input{width:200px;padding:5px 7px;border:0;outline:0;background:transparent;color:var(--ink)}.language{display:flex;padding:2px;border:1px solid var(--line);border-radius:6px;background:#fff}.language button{border:0;border-radius:4px;padding:6px 9px;background:transparent;color:var(--muted);font-size:12px}.language button[aria-pressed=true]{background:var(--teal-wash);color:var(--teal-dark);font-weight:700}.button{min-height:31px;border:1px solid #b7c6c6;border-radius:5px;padding:6px 10px;background:#fff;color:#254248;font-size:12px;font-weight:650;white-space:nowrap}.button:hover:not(:disabled){border-color:var(--teal);color:var(--teal-dark)}.primary{background:var(--teal);border-color:var(--teal);color:#fff}.primary:hover:not(:disabled){background:var(--teal-dark);border-color:var(--teal-dark);color:#fff}.danger{border-color:#dfb6b6;color:var(--red)}.danger:hover:not(:disabled){background:#fceeee;border-color:var(--red)}.notice{min-height:20px;margin:12px 0 0;color:var(--red);font-size:13px}.notice.success{color:var(--teal-dark)}.metrics{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));margin-top:26px;border:1px solid var(--line);border-radius:7px;background:var(--panel)}.metric{min-height:78px;padding:14px 17px;border-right:1px solid var(--line)}.metric:last-child{border:0}.metric label{color:var(--muted);font-size:12px}.metric strong{display:block;margin-top:4px;font-size:25px;line-height:1}.metric.attention strong{color:var(--amber)}section{margin-top:31px}.heading{display:flex;justify-content:space-between;gap:14px;align-items:baseline;margin-bottom:10px}h2{margin:0;font-size:15px;letter-spacing:0}.note,.empty{color:var(--muted);font-size:12px}.table-wrap{overflow-x:auto;border:1px solid var(--line);border-radius:7px;background:var(--panel)}table{width:100%;min-width:1000px;border-collapse:collapse}th,td{padding:12px 14px;border-bottom:1px solid #e7ecec;text-align:left;vertical-align:top;font-size:13px}th{background:#fbfcfc;color:var(--muted);font-size:11px;font-weight:700;letter-spacing:.03em;text-transform:uppercase}tbody tr:last-child td{border:0}tbody tr:hover{background:#fbfdfd}.account{min-width:200px;font-weight:650;overflow-wrap:anywhere}.status{min-width:115px}.pill{display:inline-block;border-radius:999px;padding:3px 8px;background:#edf1f1;color:#4b5b62;font-size:12px;font-weight:650}.pill.ready{background:var(--teal-wash);color:var(--teal-dark)}.pill.attention{background:var(--amber-wash);color:var(--amber)}.details{min-width:250px;max-width:320px;color:#4d5b63;line-height:1.55;white-space:pre-line}.controls{min-width:245px;display:flex;gap:6px;flex-wrap:wrap}.empty{padding:18px}.challenges{display:grid;gap:8px}.challenge{display:grid;grid-template-columns:minmax(220px,1fr) minmax(150px,220px) auto auto;gap:8px;align-items:center;padding:12px;border:1px solid var(--line);border-radius:7px;background:#fff}.challenge-title{font-size:13px;font-weight:650;overflow-wrap:anywhere}.challenge-subtitle{margin-top:3px;color:var(--muted);font-size:12px}.challenge input{width:100%;padding:7px 9px;border:1px solid #b7c6c6;border-radius:5px;outline:0}.challenge input:focus,.key:focus-within{border-color:var(--teal);box-shadow:0 0 0 3px #08766b1a}.time{min-width:155px;color:var(--muted);font-variant-numeric:tabular-nums}@media(max-width:760px){.shell{padding-top:18px}.topbar{flex-direction:column;gap:17px}.actions{justify-content:flex-start}.metrics{grid-template-columns:1fr}.metric{border-right:0;border-bottom:1px solid var(--line)}.metric:last-child{border:0}.challenge{grid-template-columns:1fr 1fr}.challenge>:first-child{grid-column:1/-1}}@media(max-width:450px){.actions{align-items:stretch}.key{width:100%}.key input{width:100%;min-width:0}.challenge{grid-template-columns:1fr}.challenge>:first-child{grid-column:auto}.button{flex:1}}
</style></head><body><main class="shell"><header class="topbar"><div class="brand"><div class="mark">CW</div><div><h1>ChatGPTWeb</h1><p class="subtitle" data-i18n="subtitle">Local operations console</p></div></div><div class="actions"><div class="language" aria-label="Language"><button type="button" data-language="zh">中文</button><button type="button" data-language="en">EN</button></div><label class="key"><input id="key" type="password" autocomplete="off" data-placeholder="apiKey" placeholder="API key"></label><button id="refresh" type="button" class="button primary" data-i18n="refresh">Refresh</button></div></header><div id="notice" class="notice" aria-live="polite"></div><div class="metrics"><div class="metric"><label data-i18n="accountTotal">Accounts</label><strong id="total">--</strong></div><div class="metric"><label data-i18n="accountReady">Available</label><strong id="ready">--</strong></div><div class="metric attention"><label data-i18n="accountAttention">Needs attention</label><strong id="attention">--</strong></div></div><section><div class="heading"><h2 data-i18n="accounts">Accounts</h2><span class="note" data-i18n="accountsHint">Live account and session state</span></div><div class="table-wrap"><table><thead><tr><th data-i18n="account">Account</th><th data-i18n="state">State</th><th data-i18n="sessions">Sessions</th><th data-i18n="usage">Usage</th><th data-i18n="details">Details</th><th data-i18n="control">Control</th></tr></thead><tbody id="accounts"></tbody></table></div></section><section><div class="heading"><h2 data-i18n="verification">Verification</h2><span class="note" data-i18n="verificationHint">Pending email or account checks</span></div><div id="challenges" class="challenges"></div></section><section><div class="heading"><h2 data-i18n="activity">Recent activity</h2><span class="note" data-i18n="activityHint">Current-process operational events</span></div><div class="table-wrap"><table><thead><tr><th data-i18n="time">Time</th><th data-i18n="account">Account</th><th data-i18n="event">Event</th><th data-i18n="detail">Detail</th></tr></thead><tbody id="activity"></tbody></table></div></section></main><script>
const translations={en:{subtitle:'Local operations console',apiKey:'API key',refresh:'Refresh',accountTotal:'Accounts',accountReady:'Available',accountAttention:'Needs attention',accounts:'Accounts',accountsHint:'Live account and session state',account:'Account',state:'State',sessions:'Sessions',usage:'Usage',details:'Details',control:'Control',verification:'Verification',verificationHint:'Pending email or account checks',activity:'Recent activity',activityHint:'Current-process operational events',time:'Time',event:'Event',detail:'Detail',noAccounts:'No accounts configured.',noChallenges:'No pending verification.',noActivity:'No local activity yet.',noUsage:'No observed upstream usage',enterKey:'Enter a valid API key.',enterCode:'Enter the verification code.',submit:'Submit',cancel:'Cancel',enable:'Enable',disable:'Disable',retryLogin:'Retry login',retryNow:'Retry now',retryManual:'Retry manually',loginProgress:'Login in progress',refreshPlan:'Refresh plan',updated:'Updated.',ready:'Ready',disabled:'Disabled',working:'Working',needsLogin:'Needs login',unavailable:'Unavailable',unknown:'Unknown',mode:'Mode',plan:'Plan',models:'Models',login:'Login',failure:'Issue',cooldown:'Retry after',authState:'Auth state',recovery:'Recovery',restored:'restored',enabled:'enabled',legacy:'legacy',observed:'observed',sourceUnavailable:'unavailable',loginReady:'ready',loginNotReady:'not ready',accountLocked:'Account unavailable',badCredentials:'Credentials rejected',needsVerification:'Verification required',riskBlocked:'Sign-in needs attention',rateLimited:'Try again later',transient:'Temporary issue',unknownFailure:'Needs attention',eventChat:'Chat completed',eventControl:'Account settings changed',eventLogin:'Login updated',eventRuntime:'Browser runtime recovered',eventGeneric:'Operational event',verificationFor:'Verification for {account}',provider:'Provider: {provider}',requests:'{count} request(s)',seconds:'{count}s remaining',minutes:'{count}m remaining'},zh:{subtitle:'本地运维控制台',apiKey:'控制台密钥',refresh:'刷新',accountTotal:'账户总数',accountReady:'可用账户',accountAttention:'需要处理',accounts:'账户',accountsHint:'实时账户与会话状态',account:'账户',state:'状态',sessions:'会话数',usage:'用量',details:'详情',control:'操作',verification:'验证',verificationHint:'等待处理的邮箱或账户验证',activity:'最近活动',activityHint:'当前进程内的运维事件',time:'时间',event:'事件',detail:'详情',noAccounts:'尚未配置账户。',noChallenges:'没有等待处理的验证。',noActivity:'当前进程还没有本地活动记录。',noUsage:'尚未观测到上游用量',enterKey:'请输入有效的控制台密钥。',enterCode:'请输入验证码。',submit:'提交',cancel:'取消',enable:'启用',disable:'停用',retryLogin:'重试登录',retryNow:'立即重试',retryManual:'手动重试',loginProgress:'登录进行中',refreshPlan:'刷新账户能力',updated:'已刷新。',ready:'可用',disabled:'已停用',working:'处理中',needsLogin:'需要登录',unavailable:'暂不可用',unknown:'未知',mode:'模式',plan:'套餐',models:'模型',login:'登录',failure:'状态',cooldown:'重试等待',authState:'认证状态',recovery:'恢复次数',restored:'已恢复',enabled:'已启用',legacy:'旧配置',observed:'已观测',sourceUnavailable:'不可用',loginReady:'可用',loginNotReady:'未就绪',accountLocked:'账户暂不可用',badCredentials:'凭据未通过验证',needsVerification:'需要完成验证',riskBlocked:'登录需要处理',rateLimited:'请稍后再试',transient:'临时异常',unknownFailure:'需要处理',eventChat:'对话已完成',eventControl:'账户设置已更新',eventLogin:'登录状态已更新',eventRuntime:'浏览器运行环境已恢复',eventGeneric:'运维事件',verificationFor:'{account} 的验证',provider:'验证方式：{provider}',requests:'{count} 次请求',seconds:'剩余 {count} 秒',minutes:'剩余约 {count} 分钟'}};
const key=document.querySelector('#key'),notice=document.querySelector('#notice'),accounts=document.querySelector('#accounts'),challenges=document.querySelector('#challenges'),activity=document.querySelector('#activity'),drafts=new Map(),submitting=new Set(),state={};let language=localStorage.getItem('chatgptweb-control-language')||(navigator.language.startsWith('zh')?'zh':'en');key.value=sessionStorage.getItem('chatgptweb-control-key')||'';
function t(name,vars={}){return (translations[language][name]||translations.en[name]||name).replace(/\{(\w+)\}/g,(_,key)=>vars[key]??'')}function setNotice(message='',success=false){notice.textContent=message;notice.classList.toggle('success',!!message&&success)}function headers(){const value=key.value.trim();return value?{Authorization:'Bearer '+value,'Content-Type':'application/json'}:{'Content-Type':'application/json'}}async function call(path,options={}){const response=await fetch(path,{...options,headers:{...headers(),...(options.headers||{})}});if(!response.ok)throw new Error(response.status===401?t('enterKey'):(await response.text())||t('unknownFailure'));return response.status===204?null:response.json()}function cell(row,value,className=''){const td=document.createElement('td');td.className=className;td.textContent=value||'--';row.append(td);return td}
function localize(){document.documentElement.lang=language==='zh'?'zh-CN':'en';document.title=language==='zh'?'ChatGPTWeb 控制台':'ChatGPTWeb Control';document.querySelectorAll('[data-i18n]').forEach(node=>node.textContent=t(node.dataset.i18n));document.querySelectorAll('[data-placeholder]').forEach(node=>node.placeholder=t(node.dataset.placeholder));document.querySelectorAll('[data-language]').forEach(node=>node.setAttribute('aria-pressed',String(node.dataset.language===language)));renderAll()}function failure(kind){return t({account_locked:'accountLocked',bad_credentials:'badCredentials',need_verification:'needsVerification',risk_blocked:'riskBlocked',rate_limited:'rateLimited',transient:'transient'}[kind]||'unknownFailure')}function label(item){if(item.login_retry_pending)return t('working');if(item.manual_disabled)return t('disabled');if(item.login_state)return t('ready');return item.login_failure_kind?t('needsLogin'):t('unavailable')}function formatUsage(usage){if(!usage||!usage.requests)return t('noUsage');const models=Object.entries(usage.models||{}).map(([name,value])=>{const tokens=['input_tokens','output_tokens','total_tokens'].filter(key=>typeof value[key]==='number').map(key=>key.replace('_tokens','')+': '+value[key]).join(', ');return name+' ('+t('requests',{count:value.requests})+(tokens?', '+tokens:'')+')'});return models.join(' | ')||t('requests',{count:usage.requests})}function details(item){const plan=item.account_plan&&item.account_plan!=='unknown'?item.account_plan+' ('+t('observed')+')':t('unknown')+' ('+t('legacy')+' '+(item.gptplus?'plus':'free')+')';const bits=[t('mode')+': '+(item.mode||'--'),t('plan')+': '+plan,t('models')+': '+(item.observed_model_count||0)+' ('+(item.observed_models_source||t('sourceUnavailable'))+')',t('login')+': '+(item.login_state?t('loginReady'):t('loginNotReady'))];if(item.login_failure_kind)bits.push(t('failure')+': '+failure(item.login_failure_kind)+' ('+(item.login_fail_count||0)+'/'+(item.max_login_failures||'--')+')');if(item.retry_after_seconds)bits.push(t('cooldown')+': '+(item.retry_after_seconds<60?t('seconds',{count:item.retry_after_seconds}):t('minutes',{count:Math.ceil(item.retry_after_seconds/60)})));if(item.persist_auth_state)bits.push(t('authState')+': '+(item.auth_state_loaded?t('restored'):t('enabled')));if(item.runtime?.recovery_count)bits.push(t('recovery')+': '+item.runtime.recovery_count);return bits.join('\n')}function retry(item){return item.retry_mode==='manual'?t('retryManual'):item.retry_mode==='cooldown'?t('retryNow'):item.retry_mode==='wait'?t('loginProgress'):t('retryLogin')}
function button(parent,item,label,action,danger=false){const node=document.createElement('button');node.type='button';node.className='button'+(danger?' danger':'');node.textContent=label;node.addEventListener('click',()=>changeAccount(item.email,action,node));parent.append(node)}async function changeAccount(account,action,node){node.disabled=true;setNotice();try{await call('/v1/accounts/'+encodeURIComponent(account)+'/control',{method:'POST',body:JSON.stringify({action})});setNotice(t('updated'),true);await refresh(true)}catch(error){setNotice(error.message);node.disabled=false}}
function renderAccounts(data){accounts.replaceChildren();const list=data.accounts||[];document.querySelector('#total').textContent=list.length;document.querySelector('#ready').textContent=list.filter(item=>item.login_state&&!item.manual_disabled).length;document.querySelector('#attention').textContent=list.filter(item=>!item.login_state||item.manual_disabled).length;if(!list.length){const row=document.createElement('tr');const empty=cell(row,t('noAccounts'),'empty');empty.colSpan=6;accounts.append(row);return}for(const item of list){const row=document.createElement('tr');cell(row,item.email,'account');const status=document.createElement('td');status.className='status';const pill=document.createElement('span');pill.className='pill '+(item.login_state&&!item.manual_disabled?'ready':item.manual_disabled||item.login_failure_kind?'attention':'');pill.textContent=label(item);status.append(pill);row.append(status);cell(row,String(item.conversation_count||0));cell(row,formatUsage(item.usage));cell(row,details(item),'details');const control=document.createElement('td');control.className='controls';if(item.manual_disabled)button(control,item,t('enable'),'enable');else{button(control,item,t('disable'),'disable',true);if(!item.login_state&&item.can_retry_login&&!item.login_retry_pending)button(control,item,retry(item),'retry_login')}button(control,item,t('refreshPlan'),'refresh_capabilities');row.append(control);accounts.append(row)}}
function renderActivity(data){activity.replaceChildren();const list=data.events||[];if(!list.length){const row=document.createElement('tr');const empty=cell(row,t('noActivity'),'empty');empty.colSpan=4;activity.append(row);return}for(const item of list){const row=document.createElement('tr');cell(row,item.at,'time');cell(row,item.account);cell(row,item.event==='chat_completed'?t('eventChat'):item.event==='account_control'?t('eventControl'):String(item.event||'').includes('login')?t('eventLogin'):String(item.event||'').includes('runtime')||String(item.event||'').includes('context')?t('eventRuntime'):t('eventGeneric'));cell(row,item.event==='account_control'?(item.message||'').replace('action: ',''):item.event==='chat_completed'?(item.message||'').replace('model: ',''):'--');activity.append(row)}}
function renderChallenges(data){challenges.replaceChildren();const list=data.challenges||[];if(!list.length){const empty=document.createElement('div');empty.className='empty';empty.textContent=t('noChallenges');challenges.append(empty);return}for(const item of list){const form=document.createElement('form');form.className='challenge';const label=document.createElement('div');label.innerHTML='<div class="challenge-title"></div><div class="challenge-subtitle"></div>';label.firstChild.textContent=t('verificationFor',{account:item.account});label.lastChild.textContent=t('provider',{provider:item.provider});const input=document.createElement('input');input.inputMode='numeric';input.autocomplete='one-time-code';input.maxLength=12;input.placeholder=t('enterCode');input.value=drafts.get(item.id)||'';input.addEventListener('input',()=>drafts.set(item.id,input.value));const submit=document.createElement('button');submit.className='button primary';submit.textContent=t('submit');const cancel=document.createElement('button');cancel.type='button';cancel.className='button danger';cancel.textContent=t('cancel');const busy=submitting.has(item.id);submit.disabled=busy;cancel.disabled=busy;form.append(label,input,submit,cancel);form.addEventListener('submit',async event=>{event.preventDefault();const code=input.value.trim();if(!code){setNotice(t('enterCode'));return}submitting.add(item.id);submit.disabled=cancel.disabled=true;try{await call('/v1/verification/'+item.id,{method:'POST',body:JSON.stringify({code})});drafts.delete(item.id);setNotice(t('updated'),true);await refresh(true)}catch(error){setNotice(error.message)}finally{submitting.delete(item.id);submit.disabled=cancel.disabled=false}});cancel.addEventListener('click',async()=>{submitting.add(item.id);submit.disabled=cancel.disabled=true;try{await call('/v1/verification/'+item.id,{method:'DELETE'});drafts.delete(item.id);setNotice(t('updated'),true);await refresh(true)}catch(error){setNotice(error.message)}finally{submitting.delete(item.id);submit.disabled=cancel.disabled=false}});challenges.append(form)}}
function renderAll(){if(state.status)renderAccounts(state.status);if(state.verification)renderChallenges(state.verification);if(state.activity)renderActivity(state.activity)}async function refresh(force=false){if(!force&&(submitting.size||challenges.contains(document.activeElement)))return;setNotice();sessionStorage.setItem('chatgptweb-control-key',key.value.trim());try{const [status,verification,events]=await Promise.all([call('/v1/account/status'),call('/v1/verification'),call('/v1/activity')]);state.status=status;state.verification=verification;state.activity=events;renderAll()}catch(error){setNotice(error.message)}}document.querySelector('#refresh').addEventListener('click',()=>refresh(true));document.querySelectorAll('[data-language]').forEach(node=>node.addEventListener('click',()=>{language=node.dataset.language;localStorage.setItem('chatgptweb-control-language',language);localize()}));localize();refresh();setInterval(refresh,5000);
</script></body></html>"""
